data.uv_unref#uv_unref:
使用的库: fuse-native


// demo

int err = uv_async_init(uv_default_loop(), &(l->async), (uv_async_cb) fuse_native_dispatch);
assert(err >= 0);

uv_unref((uv_handle_t *) &(l->async));
在 uv 代码中看到 uv_unref 其实是把当前的活跃句柄给减 1, 活跃句柄的数量是决定事件循环是否继续 uv__loop_alive 判断的条件之一, 所以如果当前任务是事件循环中剩下的最后一个任务时, 则事件循环可以不用考虑该任务, 直接进入退出程序。为什么少见 uv_ref 的调用, 可以认为 uv_async_init 等操作中已经包含了给活跃句柄加 1 的功能。
// uv 实现

void uv_unref(uv_handle_t* handle) {
uv__handle_unref(handle);
}

#define uv__handle_unref(h)                                                   \
do {                                                                        \
if (((h)->flags & UV_HANDLE_REF) == 0) break;                             \
(h)->flags &= ~UV_HANDLE_REF;                                             \
if (((h)->flags & UV_HANDLE_CLOSING) != 0) break;                         \
if (((h)->flags & UV_HANDLE_ACTIVE) != 0) uv__active_handle_rm(h);        \
}                                                                           \
while (0)

static int uv__loop_alive(const uv_loop_t* loop) {
return uv__has_active_handles(loop) ||
uv__has_active_reqs(loop) ||
loop->closing_handles != NULL;
}

data.uv_close#uv_close:
使用的库: test_worker_thread


// demo

void on_close(uv_handle_t *handle)
{
delete handle;
}

void cleanup(void* data)
{
uv_close((uv_handle_t *)data, on_close);
}

void Start(const Napi::CallbackInfo &args)
{
Napi::Env env = args.Env();
uv_loop_t *loop;
v8::Isolate* isolate = v8::Isolate::GetCurrent();
napi_get_uv_event_loop(env, &loop);
uv_prepare_t* prepare_handle = new uv_prepare_t;
uv_prepare_init(loop, prepare_handle);
uv_unref((uv_handle_t *)prepare_handle);
uv_prepare_start(prepare_handle, [](uv_prepare_t *handle) {});
node::AddEnvironmentCleanupHook(isolate, cleanup, prepare_handle);
}
可以使用 uv_close 轻易代替 uv_##name##close / uv##name##_stop, 通过如下 uv_close 的实现可知
uv_close 相比 uv_##name##_close 可以挂载一个回调函数 close_cb（close_cb 将在事件循环 阶段七 Call close callbacks 被调用
）
uv_close 实现了任意 handle 的 close


// uv 实现

void uv_close(uv_handle_t* handle, uv_close_cb close_cb) {
assert(!uv__is_closing(handle));

handle->flags |= UV_HANDLE_CLOSING;
handle->close_cb = close_cb;

switch (handle->type) {
case UV_NAMED_PIPE:
uv__pipe_close((uv_pipe_t*)handle);
break;

case UV_TTY:
uv__stream_close((uv_stream_t*)handle);
break;

case UV_TCP:
uv__tcp_close((uv_tcp_t*)handle);
break;

case UV_UDP:
uv__udp_close((uv_udp_t*)handle);
break;

case UV_PREPARE:
uv__prepare_close((uv_prepare_t*)handle);
break;

case UV_CHECK:
uv__check_close((uv_check_t*)handle);
break;

case UV_IDLE:
uv__idle_close((uv_idle_t*)handle);
break;

case UV_ASYNC:
uv__async_close((uv_async_t*)handle);
break;

case UV_TIMER:
uv__timer_close((uv_timer_t*)handle);
break;

case UV_PROCESS:
uv__process_close((uv_process_t*)handle);
break;

case UV_FS_EVENT:
uv__fs_event_close((uv_fs_event_t*)handle);
break;

case UV_POLL:
uv__poll_close((uv_poll_t*)handle);
break;

case UV_FS_POLL:
uv__fs_poll_close((uv_fs_poll_t*)handle);
/* Poll handles use file system requests, and one of them may still be
* running. The poll code will call uv__make_close_pending() for us. */
return;

case UV_SIGNAL:
uv__signal_close((uv_signal_t*) handle);
break;

default:
assert(0);
}

uv__make_close_pending(handle);
}

